2	import { screen } from "@testing-library/react";
3	import { renderWithProviders } from "./helpers";
4	import Portfolio from "@/routes/Portfolio";
5	
6	// ---------------------------------------------------------------------------
7	// Mocks — hook-level, following codebase conventions
8	// ---------------------------------------------------------------------------
9	
10	vi.mock("@/features/session/context", async () => {
11	  const actual = await vi.importActual<typeof import("@/features/session/context")>(
12	    "@/features/session/context",
13	  );
14	  return {
15	    ...actual,
16	    useSession: vi.fn(),
17	  };
18	});
19	
