21	  useAccountRisk: vi.fn(),
22	  useMarkets: vi.fn(),
23	}));
24	
25	import { useSession } from "@/features/session/context";
26	import { useAccountRisk, useMarkets } from "@/lib/query/hooks";
27	
28	const mockUseSession = vi.mocked(useSession);
29	const mockUseAccountRisk = vi.mocked(useAccountRisk);
30	const mockUseMarkets = vi.mocked(useMarkets);
31	
32	// ---------------------------------------------------------------------------
33	// Shared fixtures
34	// ---------------------------------------------------------------------------
35	
36	const unconfiguredSession = {
37	  session: { accountId: "", agentId: "" },
38	  setAccountId: vi.fn(),
39	  setAgentId: vi.fn(),
40	  isConfigured: false,
41	};
42	
43	const configuredSession = {
44	  session: { accountId: "acc-123", agentId: "agent-1" },
45	  setAccountId: vi.fn(),
46	  setAgentId: vi.fn(),
47	  isConfigured: true,
48	};
49	
50	const emptyQueryResult = {
51	  data: undefined,
52	  isLoading: false,
53	  error: null,
54	  isSuccess: false,
55	  isError: false,
56	  isPending: false,
57	  isLoadingError: false,
58	  isRefetchError: false,
59	  status: "pending" as const,
60	  fetchStatus: "idle" as const,
61	  isFetching: false,
62	  isPlaceholderData: false,
63	  isRefetching: false,
64	  isStale: false,
65	  dataUpdatedAt: 0,
66	  errorUpdatedAt: 0,
67	  failureCount: 0,
68	  failureReason: null,
69	  errorUpdateCount: 0,
70	  refetch: vi.fn(),
71	  promise: Promise.resolve(undefined as never),
72	};
73	
74	function makeRiskData(overrides: {
75	  status?: "healthy" | "warning" | "critical";
76	  markets?: Array<{
77	    marketId: string;
78	    minAsset: number;
79	    capacityConsumed: number;
80	    utilization: number;
81	    commandCount: number;
82	    lastOrderId: string;
83	    lastCommandId: string;
84	    updatedAt: string;
85	  }>;
86	  updatedAt?: string;
87	} = {}) {
88	  return {
89	    account: {
90	      id: "acc-123",
91	      risk: {
92	        minAssets: {
93	          overall: 42.5,
94	          markets: overrides.markets ?? [],
95	        },
96	        capacityIndicators: {
97	          limit: 1000.0,
98	          available: 750.25,
99	          consumed: 249.75,
100	          utilization: 0.24975,
101	          status: overrides.status ?? "healthy",
102	        },
103	        updatedAt: overrides.updatedAt ?? "2026-04-09T12:30:00Z",
104	      },
105	    },
106	    meta: { apiVersion: "1.0", timestamp: "2026-04-09T12:30:00Z" },
107	  };
108	}
109	
110	const defaultMarkets = {
111	  markets: [] as Array<{ id: string; title: string; status: string; liquidity: number; volume: number; expires_at: string }>,
112	  count: 0,
113	  meta: { apiVersion: "1.0", timestamp: "2026-04-09T00:00:00Z" },
114	};
115	
116	// ---------------------------------------------------------------------------
117	// Tests
118	// ---------------------------------------------------------------------------
119	
120	describe("Portfolio", () => {
121	  beforeEach(() => {
122	    vi.clearAllMocks();
123	    mockUseMarkets.mockReturnValue({ ...emptyQueryResult, data: defaultMarkets } as ReturnType<typeof useMarkets>);
124	  });
125	
126	  // -------------------------------------------------------------------------
127	  // Step 1 — Unconfigured session
128	  // -------------------------------------------------------------------------
129	  it("renders account prompt when no session configured", () => {
130	    mockUseSession.mockReturnValue(unconfiguredSession);
131	    mockUseAccountRisk.mockReturnValue({ ...emptyQueryResult } as ReturnType<typeof useAccountRisk>);
132	
133	    renderWithProviders(<Portfolio />);
134	    expect(screen.getByText(/Set your Account ID/)).toBeInTheDocument();
135	  });
136	
137	  // -------------------------------------------------------------------------
138	  // Step 2 — Loading state
139	  // -------------------------------------------------------------------------
140	  it("renders loading page while risk data loads", () => {
141	    mockUseSession.mockReturnValue(configuredSession);
142	    mockUseAccountRisk.mockReturnValue({
143	      ...emptyQueryResult,
144	      isLoading: true,
145	    } as ReturnType<typeof useAccountRisk>);
146	
147	    const { container } = renderWithProviders(<Portfolio />);
148	    // LoadingPage renders an SVG spinner
149	    expect(container.querySelector("svg")).toBeInTheDocument();
150	  });
151	
152	  // -------------------------------------------------------------------------
153	  // Step 3 — Error state
154	  // -------------------------------------------------------------------------
155	  it("renders error message when risk fetch fails", () => {
156	    mockUseSession.mockReturnValue(configuredSession);
157	    mockUseAccountRisk.mockReturnValue({
158	      ...emptyQueryResult,
159	      error: new Error("fail"),
160	    } as ReturnType<typeof useAccountRisk>);
161	
162	    renderWithProviders(<Portfolio />);
163	    expect(screen.getByText("Account not found or no positions yet.")).toBeInTheDocument();
164	  });
165	
166	  // -------------------------------------------------------------------------
167	  // Step 4 — Full data rendering (MetricCards)
168	  // -------------------------------------------------------------------------
169	  it("renders portfolio heading and metric cards with full data", () => {
170	    mockUseSession.mockReturnValue(configuredSession);
171	    mockUseAccountRisk.mockReturnValue({
172	      ...emptyQueryResult,
173	      data: makeRiskData(),
174	      isSuccess: true,
175	    } as ReturnType<typeof useAccountRisk>);
176	
177	    renderWithProviders(<Portfolio />);
178	
179	    expect(screen.getByText("Portfolio")).toBeInTheDocument();
180	    expect(screen.getByText("1000.00")).toBeInTheDocument(); // Limit
181	    expect(screen.getByText("750.25")).toBeInTheDocument(); // Available
182	    expect(screen.getByText("249.75")).toBeInTheDocument(); // Consumed
183	    expect(screen.getByText("25.0%")).toBeInTheDocument(); // Utilization
184	    expect(screen.getByText("healthy")).toBeInTheDocument(); // Health
185	    expect(screen.getByText("42.50")).toBeInTheDocument(); // Min Asset (Overall)
186	  });
187	
188	  // -------------------------------------------------------------------------
189	  // Step 5 — Health status colors
190	  // -------------------------------------------------------------------------
191	  it.each([
192	    { status: "healthy" as const, color: "var(--color-success)" },
193	    { status: "warning" as const, color: "var(--color-warning)" },
194	    { status: "critical" as const, color: "var(--color-danger)" },
195	  ])("renders health status '$status' with correct color", ({ status, color }) => {
196	    mockUseSession.mockReturnValue(configuredSession);
197	    mockUseAccountRisk.mockReturnValue({
198	      ...emptyQueryResult,
199	      data: makeRiskData({ status }),
200	      isSuccess: true,
201	    } as ReturnType<typeof useAccountRisk>);
202	
203	    renderWithProviders(<Portfolio />);
204	
205	    const healthValue = screen.getByText(status);
206	    expect(healthValue).toHaveStyle({ color });
207	  });
208	
209	  // -------------------------------------------------------------------------
210	  // Step 6 — Timestamp display
211	  // -------------------------------------------------------------------------
