  updatedAt?: string;
} = {}) {
  return {
    account: {
      id: "acc-123",
      risk: {
        minAssets: {
          overall: 42.5,
          markets: overrides.markets ?? [],
        },
        capacityIndicators: {
          limit: 1000.0,
          available: 750.25,
          consumed: 249.75,
